  ('aboriginal-f29af906-moex-00176', 'aboriginal-f29af906', 'aboriginal-f29af906-moex-110-6ed013db', 'sub-aboriginal-f29af906-11', NULL, 'single_choice', '依司法院大法官解釋，關於服兵役之義務與宗教信仰自由，下列敘述何者錯誤？', '["憲法保障人民有信仰與不信仰任何宗教之自由，國家不得對特定之宗教加以獎勵或禁制，或對人民 特定信仰給予優待或不利益", "立法者對於免役及禁役之規定，屬立法政策之考量，非為助長、促進或限制宗教而設，且無助長、 促進或限制宗教之效果", "內在信仰之自由，涉及思想、言論、信念及精神之層次，應受絕對之保障，故因宗教因素致不適服 役時，應免除其服兵役之義務", "人民如何履行兵役義務，憲法本身並無明文規定，有關人民服兵役之重要事項，應由立法者斟酌國 家安全、社會發展之需要，以法律定之"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:02+00:00", "source_pdf_sha1": "f61a2d735529", "answer_pdf_sha1": "f402bd417587", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "509", "s": "0214", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "地政"}'::jsonb, NULL),
